scores = {'Иван': 85, 'Мария': 92, 'Пётр': 78}

# Перебор по ключам (по умолчанию)
for name in scores:
    print(name)

# Перебор по парам — самый частый вариант
for name, score in scores.items():
    print(f'{name}: {score} баллов')

# Перебор только значений
total = 0
for score in scores.values():
    total += score
print(f'Средний балл: {total / len(scores):.1f}')

# update() — добавить/обновить сразу несколько ключей
person = {'name': 'Иван', 'age': 30}
person.update({'age': 31, 'city': 'Москва', 'job': 'разработчик'})
print(person)
# {'name': 'Иван', 'age': 31, 'city': 'Москва', 'job': 'разработчик'}

# setdefault() — установить значение только если ключа нет
d = {'a': 1}
d.setdefault('a', 99)   # ключ есть — не меняет
d.setdefault('b', 99)   # ключа нет — ставит 99
print(d)  # {'a': 1, 'b': 99}

# Создание словаря из двух списков через zip()
keys = ['name', 'age', 'city']
values = ['Мария', 25, 'СПб']
profile = dict(zip(keys, values))
print(profile)  # {'name': 'Мария', 'age': 25, 'city': 'СПб'}

# Очистка словаря
profile.clear()
print(profile)  # {}

# Словарь «число → квадрат»
squares = {n: n ** 2 for n in range(1, 6)}
print(squares)  # {1: 1, 2: 4, 3: 9, 4: 16, 5: 25}

# С условием — только чётные
even_sq = {n: n ** 2 for n in range(1, 11) if n % 2 == 0}
print(even_sq)  # {2: 4, 4: 16, 6: 36, 8: 64, 10: 100}

# Перевернуть словарь (ключи ↔ значения)
original = {'a': 1, 'b': 2, 'c': 3}
inverted = {v: k for k, v in original.items()}
print(inverted)  # {1: 'a', 2: 'b', 3: 'c'}

# Перевести все ключи строкового словаря в нижний регистр
data = {'Name': 'Иван', 'AGE': 30, 'City': 'Москва'}
normalized = {k.lower(): v for k, v in data.items()}
print(normalized)  # {'name': 'Иван', 'age': 30, 'city': 'Москва'}

# Подсчёт вхождений
words = ['python', 'java', 'python', 'c++', 'java', 'python']
counts = {}

for word in words:
    if word in counts:
        counts[word] += 1
    else:
        counts[word] = 1

print(counts)  # {'python': 3, 'java': 2, 'c++': 1}

# То же самое через get()
counts2 = {}
for word in words:
    counts2[word] = counts2.get(word, 0) + 1

print(counts2)  # {'python': 3, 'java': 2, 'c++': 1}

# Словарь с вложенными словарями
users = {
    'ivan': {
        'name': 'Иван Петров',
        'age': 30,
        'active': True
    },
    'maria': {
        'name': 'Мария Сидорова',
        'age': 25,
        'active': False
    }
}

# Доступ к вложенным данным
print(users['ivan']['name'])    # Иван Петров
print(users['maria']['age'])    # 25

# Перебор
for username, info in users.items():
    status = 'активен' if info['active'] else 'неактивен'
    print(f'{username}: {info["name"]} — {status}')

